const planningToday='2026-06-19';
let agendaFilter='all';
let activeDetailProject=null;
var financeTransactions=[];
const uiFilters={
  projectStart:'',
  projectEnd:'',
  agendaSearch:'',
  agendaStart:'2026-06-01',
  agendaEnd:'2026-06-30',
  agendaProject:'all',
  agendaOwner:'all',
  updateSearch:'',
  updateStart:'',
  updateEnd:'',
  financeSearch:'',
  financeStart:'',
  financeEnd:''
};
const dashboardCalendarRootId='dashboardMonthOverview';

const addDays=(date,days)=>{const d=new Date(date+'T00:00:00');d.setDate(d.getDate()+days);return d.toISOString().slice(0,10)};
const dayDiff=(a,b)=>a&&b?Math.round((new Date(a+'T00:00:00')-new Date(b+'T00:00:00'))/864e5):0;
const uid=prefix=>prefix+'-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,6);
const thaiFullDate=d=>d?new Intl.DateTimeFormat('th-TH',{weekday:'short',day:'numeric',month:'short'}).format(new Date(d+'T00:00:00')):'ยังไม่กำหนด';
const financeRoles=['admin','accounting'];
const itemTemplates=['ยืนยัน Scope และผู้เกี่ยวข้อง','รวบรวมข้อมูลและ Requirement','จัดทำ Draft / Prototype','ทบทวนภายในทีม','ส่งให้ลูกค้าตรวจสอบ','เก็บ Feedback และประเด็นแก้ไข','ปรับปรุงรอบที่ 1','ทดสอบและตรวจคุณภาพ','ขออนุมัติผลส่งมอบ','ส่งมอบและบันทึกบทเรียน'];
const jmtStreams=[
  ['Data Foundation & Integration','อนุชา กิตติ',78,'ออกแบบแหล่งข้อมูลและเชื่อมต่อข้อมูลต้นทาง'],
  ['KPI Configuration','พิมพ์ชนก แสงใส',92,'กำหนด KPI สูตรคำนวณ และเกณฑ์เป้าหมาย'],
  ['Executive Dashboard','ณัฐวุฒิ วงศ์ดี',84,'พัฒนา Dashboard สำหรับผู้บริหารและหัวหน้าทีม'],
  ['UAT & Data Validation','ศิริพร ใจดี',63,'ทดสอบความถูกต้องของข้อมูลและรับรองผล'],
  ['Training & Go-live','กานต์ เทพดี',48,'อบรมผู้ใช้งาน เตรียมคู่มือ และนำระบบขึ้นใช้งาน']
];

function makeItems(streamIndex,owner,base){return itemTemplates.map((title,i)=>{const start=addDays('2026-06-03',streamIndex*2+i*2);const due=addDays(start,3+(i%3));const raw=Math.max(0,Math.min(100,base+(4-i)*9));return{id:`item-${streamIndex}-${i}`,title,owner,start,due,followUp:addDays(due,-1),priority:i===4||i===8?'high':i%3===0?'medium':'low',note:i===4?'ติดตาม Feedback และผู้อนุมัติจากลูกค้า':i===8?'ตรวจรายการค้างก่อนขออนุมัติ':'ติดตามผลและอัปเดตหลักฐานในระบบ',progress:raw>=95?100:Math.round(raw/5)*5};})}
function makeJmtWorkstreams(){return jmtStreams.map((s,i)=>({id:`jmt-ws-${i+1}`,title:s[0],owner:s[1],start:addDays('2026-06-03',i*2),due:addDays('2026-07-05',i-4),followUp:addDays(planningToday,(i%5)-2),priority:i===3?'high':'medium',note:s[3],items:makeItems(i,s[1],s[2])}))}
function makeGenericStreams(project){return (project.tasks||[]).map((t,i)=>({id:`${project.id}-ws-${i+1}`,title:t[0],owner:t[2],start:addDays('2026-06-05',i*3),due:addDays(project.deadline,-(project.tasks.length-i-1)*4),followUp:addDays(planningToday,i-1),priority:i===project.tasks.length-1?'high':'medium',note:`ติดตามผล ${t[0]} และอัปเดตสิ่งที่ต้องดำเนินการครั้งถัดไป`,items:itemTemplates.slice(0,Math.min(5+i,10)).map((name,j)=>({id:`${project.id}-${i}-${j}`,title:name,owner:t[2],start:addDays('2026-06-05',i*3+j),due:addDays('2026-06-10',i*3+j*2),followUp:addDays(planningToday,i+j-2),priority:j===2?'high':'medium',note:'อัปเดตผล หลักฐาน และประเด็นที่ต้องติดตาม',progress:Math.max(0,Math.min(100,t[1]+(2-j)*10))}))}))}
function makeMeetings(project){return [{id:`${project.id}-kickoff`,title:'ประชุม Kickoff / Sync Scope',date:addDays('2026-06-19',project.id==='jmt'?0:1),time:'10:00',owner:project.manager,type:'meeting',note:'ยืนยันขอบเขตงาน ผู้รับผิดชอบ และสิ่งที่ต้องส่งมอบ'}, {id:`${project.id}-weekly`,title:'Weekly Progress Review',date:addDays('2026-06-19',project.id==='jmt'?3:4),time:'14:00',owner:project.manager,type:'meeting',note:'ตรวจ Progress, Issue, Next action และความเสี่ยง'}, {id:`${project.id}-client`,title:'ประชุมอัปเดตลูกค้า',date:addDays('2026-06-19',project.id==='sdc'?5:6),time:'15:30',owner:project.manager,type:'meeting',note:'สรุปงานที่เสร็จ งานค้าง และขอการอนุมัติ'}]}
function normalizePlanningData(){projects.forEach(p=>{if(!Array.isArray(p.workstreams)||!p.workstreams.length)p.workstreams=p.id==='jmt'?makeJmtWorkstreams():makeGenericStreams(p);if(!Array.isArray(p.meetings)||!p.meetings.length)p.meetings=makeMeetings(p);if(!p.permissions)p.permissions={view:['admin','executive','manager','accounting'],finance:p.id==='sdc'?['admin','accounting']:['admin','executive','accounting'],edit:['admin','manager']}});recalculateAll();save()}
function streamProgress(ws){return Number.isFinite(ws.reportedProgress)?ws.reportedProgress:(ws.items?.length?Math.round(ws.items.reduce((sum,i)=>sum+Number(i.progress||0),0)/ws.items.length):0)}
function recalculateAll(){projects.forEach(p=>{p.workstreams.forEach(ws=>ws.progress=streamProgress(ws));p.progress=p.workstreams.length?Math.round(p.workstreams.reduce((sum,w)=>sum+w.progress,0)/p.workstreams.length):0;p.status=p.progress===100?'done':p.workstreams.some(w=>dayDiff(w.due,planningToday)<0&&w.progress<100)?'risk':'active'})}
function flattenFollowUps(){return visibleProjects().flatMap(p=>p.workstreams.flatMap(ws=>[{kind:'workstream',project:p,stream:ws,item:null,title:ws.title,owner:ws.owner,date:ws.followUp,due:ws.due,priority:ws.priority,note:ws.note,progress:ws.progress},...(ws.items||[]).filter(i=>i.progress<100).map(i=>({kind:'item',project:p,stream:ws,item:i,title:i.title,owner:i.owner,date:i.followUp,due:i.due,priority:i.priority,note:i.note,progress:i.progress}))])).filter(x=>x.progress<100&&validDate(x.date)).sort((a,b)=>validDate(a.date)-validDate(b.date))}
function canSeeFinance(project){return financeRoles.includes(currentRole)||(project.permissions?.finance||[]).includes(currentRole)}
function secureMoney(project,value){return canSeeFinance(project)?money(value):'<span class="money-hidden">ซ่อนตามสิทธิ์</span>'}
function visibleProjectsByPermission(){return visibleProjects().filter(p=>currentRole==='admin'||(p.permissions?.view||[]).includes(currentRole)||currentRole==='team')}
function followState(date){const diff=dayDiff(date,planningToday);return diff<0?'overdue':diff===0?'today':'upcoming'}
function renderAgenda(){const all=flattenFollowUps(),filtered=all.filter(x=>agendaFilter==='all'||followState(x.date)===agendaFilter),overdue=all.filter(x=>followState(x.date)==='overdue').length,today=all.filter(x=>followState(x.date)==='today').length,week=all.filter(x=>dayDiff(x.date,planningToday)>=0&&dayDiff(x.date,planningToday)<=7).length,meetings=visibleProjectsByPermission().reduce((n,p)=>n+(p.meetings||[]).filter(m=>dayDiff(m.date,planningToday)>=0&&dayDiff(m.date,planningToday)<=7).length,0);$('#agendaStats').innerHTML=[['เลยกำหนดติดตาม',overdue,'!','#ef5b5b','ต้องดำเนินการทันที'],['ต้องติดตามวันนี้',today,'☑','#ff9f43','ตามแผนประจำวัน'],['7 วันข้างหน้า',week,'◴','#315bea','เตรียมการล่วงหน้า'],['ประชุมใน 7 วัน',meetings,'◎','#19a8b8','รวม Meeting / Review']].map(x=>`<div class="stat-card" style="--accent:${x[3]}"><div class="stat-top"><span>${x[0]}</span><span class="stat-icon">${x[2]}</span></div><div class="stat-value">${x[1]} รายการ</div><div class="stat-note">${x[4]}</div></div>`).join('');$('#agendaList').innerHTML=filtered.slice(0,30).map(x=>{const state=followState(x.date);return`<div class="follow-card"><div class="follow-date ${state}">${new Date(x.date+'T00:00:00').getDate()}<small>${new Intl.DateTimeFormat('th-TH',{month:'short'}).format(new Date(x.date+'T00:00:00'))}</small></div><div class="follow-copy"><b>${x.title}</b><p>${x.note}</p><div class="follow-meta"><span class="priority ${x.priority}">${x.priority==='high'?'สำคัญสูง':x.priority==='medium'?'ปานกลาง':'ทั่วไป'}</span><span>${x.project.name} › ${x.stream.title}</span><span>ผู้รับผิดชอบ ${x.owner}</span></div></div><div class="follow-action"><small>${state==='overdue'?`เลยกำหนด ${Math.abs(dayDiff(x.date,planningToday))} วัน`:state==='today'?'ติดตามวันนี้':`อีก ${dayDiff(x.date,planningToday)} วัน`}</small><button data-open-project="${x.project.id}">เปิดรายละเอียด</button></div></div>`}).join('')||'<div class="empty-state">ไม่มีรายการติดตามตามเงื่อนไขนี้</div>';renderWeek(all);renderCalendar();$$('[data-open-project]').forEach(b=>b.onclick=()=>showDetail(b.dataset.openProject))}
function renderWeek(items){const days=Array.from({length:7},(_,i)=>addDays(planningToday,i));$('#weekTimeline').innerHTML=days.map(d=>{const events=items.filter(x=>x.date===d).slice(0,4);return`<div class="week-day"><div class="week-date"><b>${new Date(d+'T00:00:00').getDate()}</b>${new Intl.DateTimeFormat('th-TH',{weekday:'short',month:'short'}).format(new Date(d+'T00:00:00'))}</div><div class="week-events">${events.length?events.map(x=>`<div class="week-event" style="border-color:${x.project.color}"><b>${x.title}</b>${x.project.name} · ${x.owner}</div>`).join(''):'<span class="activity-time">ไม่มีนัดติดตาม</span>'}</div></div>`}).join('')}
function calendarEvents(){const follow=flattenFollowUps().map(x=>({date:x.date,title:x.title,project:x.project,owner:x.owner,type:'follow'}));const meetings=visibleProjectsByPermission().flatMap(p=>(p.meetings||[]).map(m=>({...m,project:p})));const due=visibleProjectsByPermission().flatMap(p=>p.workstreams.map(w=>({date:w.due,title:'Deadline: '+w.title,project:p,owner:w.owner,type:'deadline'})));return [...follow,...meetings,...due]}
function renderCalendar(){const start='2026-06-01',days=30,head=['จันทร์','อังคาร','พุธ','พฤหัส','ศุกร์','เสาร์','อาทิตย์'];const events=calendarEvents();$('#calendarGrid').innerHTML=`<div class="calendar-grid">${head.map(h=>`<div class="calendar-head">${h}</div>`).join('')}${Array.from({length:days},(_,i)=>addDays(start,i)).map(d=>{const dayEvents=events.filter(e=>e.date===d).slice(0,4);return`<div class="calendar-day ${d===planningToday?'is-today':''}"><div class="calendar-num">${new Date(d+'T00:00:00').getDate()}<span>${d===planningToday?'วันนี้':''}</span></div>${dayEvents.map(e=>`<div class="calendar-event ${e.type}" style="border-color:${e.project.color}"><b>${e.type==='meeting'?(e.time||'')+' ':''}${e.title}</b>${e.project.name} · ${e.owner}</div>`).join('')}</div>`}).join('')}</div>`}
function workstreamMarkup(p,ws,index){const prog=streamProgress(ws);return`<div class="workstream ${index===0?'open':''}" data-workstream="${ws.id}"><div class="workstream-head"><span class="work-number">${String(index+1).padStart(2,'0')}</span><div class="work-title"><b>${ws.title}</b><small>${ws.owner} · ${ws.items.length} รายละเอียด · ส่ง ${dateTH(ws.due)}</small></div><div class="progress-wrap"><div class="mini-progress"><span style="width:${prog}%;background:${p.color}"></span></div></div><span class="work-percent">${prog}%</span><span class="work-chevron">⌄</span></div><div class="workstream-body"><div class="next-follow"><b>ติดตามครั้งถัดไป: ${thaiFullDate(ws.followUp)}</b>${ws.note}</div>${ws.items.map(item=>`<div class="check-row"><button class="check-toggle ${item.progress===100?'done':''}" data-toggle-item="${item.id}" data-stream-id="${ws.id}" data-project-id="${p.id}">${item.progress===100?'✓':''}</button><div class="check-copy"><b>${item.title}</b><small>${item.note}</small></div><span class="check-owner">${item.owner}</span><span class="check-date">${dateTH(item.due)}</span><label class="check-progress"><input type="number" min="0" max="100" value="${item.progress}" data-progress-item="${item.id}" data-stream-id="${ws.id}" data-project-id="${p.id}">%</label></div>`).join('')}<button class="text-button" data-add-checklist="${ws.id}" data-project-id="${p.id}">＋ เพิ่มรายละเอียดในงานนี้</button></div></div>`}
function planningShowDetail(id){const p=projects.find(x=>x.id===id);if(!p)return;activeDetailProject=id;recalculateAll();const totalItems=p.workstreams.reduce((n,w)=>n+w.items.length,0),done=p.workstreams.reduce((n,w)=>n+w.items.filter(i=>i.progress===100).length,0),next=flattenFollowUps().filter(x=>x.project.id===id)[0];$('#projectDetail').innerHTML=`<div class="detail-hero"><div class="detail-nav"><button class="back-button" data-goto="projects">← กลับไปโปรเจกต์</button><span class="status-badge ${p.status}">${statusText[p.status]}</span></div><div class="detail-title"><span class="project-logo" style="background:${p.color}">${p.name.slice(0,2).toUpperCase()}</span><div><h2>${p.name}</h2><p>${p.client} · Project Owner: ${p.manager}</p></div></div><div class="detail-kpis"><div><small>Progress อัตโนมัติ</small><b>${p.progress}%</b></div><div><small>งานหลัก</small><b>${p.workstreams.length} งาน</b></div><div><small>รายละเอียดสำเร็จ</small><b>${done}/${totalItems}</b></div><div><small>มูลค่าโครงการ</small><b>${secureMoney(p,p.value)}</b></div></div></div><div class="detail-grid"><div class="panel"><div class="panel-head"><div><span class="eyebrow">WORK BREAKDOWN STRUCTURE</span><h3>ภาพรวมและรายละเอียดงาน</h3></div><div class="detail-actions"><button class="secondary" data-open-planning data-project-id="${p.id}">＋ งานหลัก</button><button class="primary" data-open-update data-project-id="${p.id}">＋ อัปเดต Progress</button></div></div><div class="work-summary"><div><small>งานทั้งหมด</small><b>${p.workstreams.length}</b></div><div><small>รายการรายละเอียด</small><b>${totalItems}</b></div><div><small>สำเร็จแล้ว</small><b>${done}</b></div></div>${p.workstreams.map((ws,i)=>workstreamMarkup(p,ws,i)).join('')}</div><div class="detail-side-stack"><div class="panel"><span class="eyebrow">NEXT FOLLOW-UP</span><h3>การติดตามครั้งถัดไป</h3>${next?`<div class="next-follow"><b>${thaiFullDate(next.date)} · ${next.title}</b>${next.note}<br>ผู้รับผิดชอบ: ${next.owner}</div>`:'<div class="empty-state">ไม่มีรายการค้างติดตาม</div>'}<div class="timeline-strip">${p.workstreams.slice().sort((a,b)=>new Date(a.due)-new Date(b.due)).map(w=>`<div class="timeline-event"><b>${w.title}</b><span>${dateTH(w.start)} → ${dateTH(w.due)} · ${w.owner}</span></div>`).join('')}${(p.meetings||[]).map(m=>`<div class="timeline-event"><b>${m.title}</b><span>${dateTH(m.date)} ${m.time} · ${m.owner}</span></div>`).join('')}</div></div><div class="panel"><span class="eyebrow">PROJECT DETAILS</span><h3>ข้อมูลโครงการ</h3><div class="permission-row"><b>บริษัทผู้รับจ้าง</b><span>${p.company}</span></div><div class="permission-row"><b>บริษัทลูกค้า</b><span>${p.client}</span></div><div class="permission-row"><b>ผู้ดูแลโครงการ</b><span>${p.manager}</span></div><div class="permission-row"><b>มูลค่า / หัก ณ ที่จ่าย</b><span>${secureMoney(p,p.value)} / ${canSeeFinance(p)?p.wht+'%':'ซ่อน'}</span></div></div></div></div>`;showView('detail');bindDynamic();bindPlanningActions();$$('[data-open-update]').forEach(b=>b.onclick=()=>openUpdate(b.dataset.projectId))}
function bindPlanningActions(){$$('.workstream-head').forEach(h=>h.onclick=()=>h.closest('.workstream').classList.toggle('open'));$$('[data-open-planning]').forEach(b=>b.onclick=()=>openPlanning(b.dataset.projectId));$$('[data-add-checklist]').forEach(b=>b.onclick=()=>openPlanning(b.dataset.projectId,'checklist',b.dataset.addChecklist));$$('[data-toggle-item]').forEach(b=>b.onclick=()=>{const p=projects.find(x=>x.id===b.dataset.projectId),ws=p.workstreams.find(w=>w.id===b.dataset.streamId),item=ws.items.find(i=>i.id===b.dataset.toggleItem);delete ws.reportedProgress;item.progress=item.progress===100?0:100;recalculateAll();save();planningShowDetail(p.id);renderAgenda();showToast('อัปเดต Progress อัตโนมัติแล้ว')});$$('[data-progress-item]').forEach(input=>input.onchange=()=>{const p=projects.find(x=>x.id===input.dataset.projectId),ws=p.workstreams.find(w=>w.id===input.dataset.streamId),item=ws.items.find(i=>i.id===input.dataset.progressItem);delete ws.reportedProgress;item.progress=Math.max(0,Math.min(100,Number(input.value)));recalculateAll();save();planningShowDetail(p.id);renderAgenda();showToast('คำนวณภาพรวมใหม่แล้ว')})}
function fillPlanParents(){const p=projects.find(x=>x.id===$('#planProject').value);$('#planParent').innerHTML=(p?.workstreams||[]).map(w=>`<option value="${w.id}">${w.title}</option>`).join('')}
function openPlanning(projectId,type='workstream',parentId=''){const allowed=visibleProjects();$('#planProject').innerHTML=allowed.map(p=>`<option value="${p.id}">${p.name}</option>`).join('');$('#planProject').value=projectId||allowed[0]?.id;$('#planType').value=type;fillPlanParents();if(parentId)$('#planParent').value=parentId;$('#parentField').classList.toggle('hidden',type!=='checklist');$('#planStart').value=planningToday;$('#planDue').value=addDays(planningToday,7);$('#planFollowUp').value=addDays(planningToday,1);$('#planningModal').classList.add('open')}
function closePlanning(){$('#planningModal').classList.remove('open')}

normalizePlanningData();
roleConfig.admin={title:'ผู้ดูแลระบบ',projects:['all']};
titles.agenda='งานติดตามวันนี้';
renderFinance=function(){const p=visibleProjectsByPermission(),value=p.reduce((a,x)=>canSeeFinance(x)?a+x.value:a,0),cost=p.reduce((a,x)=>canSeeFinance(x)?a+x.cost:a,0),profit=value-cost,wht=p.reduce((a,x)=>canSeeFinance(x)?a+x.value*x.wht/100:a,0);$('#financeStats').innerHTML=[['มูลค่าที่มีสิทธิ์เห็น',money(value),'฿','#315bea'],['ค่าใช้จ่ายที่มีสิทธิ์เห็น',money(cost),'↘','#ef5b5b'],['กำไรคาดการณ์',money(profit),'↗','#38c58b'],['ภาษีหัก ณ ที่จ่าย',money(wht),'%','#ff9f43']].map(x=>`<div class="stat-card" style="--accent:${x[3]}"><div class="stat-top"><span>${x[0]}</span><span class="stat-icon">${x[2]}</span></div><div class="stat-value">${x[1]}</div></div>`).join('');$('#financeTable').innerHTML=p.map(x=>`<tr><td class="finance-name"><b>${x.client}</b><small>${x.name} · ${x.company}</small></td><td>${secureMoney(x,x.value)}</td><td>${secureMoney(x,x.cost)}</td><td>${canSeeFinance(x)?`<span class="delta">${money(x.value-x.cost)}</span>`:'<span class="money-hidden">ซ่อนตามสิทธิ์</span>'}</td><td>${canSeeFinance(x)?`${x.wht}% (${money(x.value*x.wht/100)})`:'<span class="money-hidden">ซ่อน</span>'}</td><td><span class="status-badge ${x.paid.includes('ครบ')?'done':'active'}">${canSeeFinance(x)?x.paid:'เห็นเฉพาะสถานะงาน'}</span></td></tr>`).join('')};
renderUsers=function(){const users=[['กานต์ เทพดี','ผู้ดูแลระบบ','ทุกโปรเจกต์'],['สุทธา ผู้บริหาร','ผู้บริหาร','ทุกโปรเจกต์ / เงินเฉพาะที่อนุญาต'],['ณัฐวุฒิ วงศ์ดี','ผู้จัดการโครงการ','SDDS, JMT'],['พิมพ์ชนก แสงใส','ผู้จัดการโครงการ','SDC'],['ศิริพร ใจดี','ทีมงาน','SDDS, CRM'],['วริศรา มั่นคง','ฝ่ายบัญชี','เงินทุกโปรเจกต์']];$('#userList').innerHTML=`<div class="permission-grid">${projects.map(p=>`<div class="permission-project"><h4>${p.name}</h4><div class="permission-switches">${['executive','manager','team','accounting'].map(role=>`<label><input type="checkbox" ${p.permissions.view.includes(role)?'checked':''} ${currentRole==='admin'?'':'disabled'} data-permission-project="${p.id}" data-permission-role="${role}" data-permission-type="view"> เห็นงาน: ${role}</label>`).join('')}${['executive','manager','team','accounting'].map(role=>`<label><input type="checkbox" ${p.permissions.finance.includes(role)?'checked':''} ${currentRole==='admin'?'':'disabled'} data-permission-project="${p.id}" data-permission-role="${role}" data-permission-type="finance"> เห็นเงิน: ${role}</label>`).join('')}</div></div>`).join('')}</div><div style="margin-top:18px">${users.map(u=>`<div class="user-row"><div class="user-info"><span class="avatar">${u[0].slice(0,2)}</span><div><b>${u[0]}</b><small>ใช้งานล่าสุด วันนี้</small></div></div><select ${currentRole==='admin'?'':'disabled'}><option>${u[1]}</option></select><span class="project-tags">${u[2]}</span></div>`).join('')}</div>`;$$('[data-permission-project]').forEach(input=>input.onchange=()=>{if(currentRole!=='admin')return showToast('แก้สิทธิ์ได้เฉพาะผู้ดูแลระบบเท่านั้น');const p=projects.find(x=>x.id===input.dataset.permissionProject),list=p.permissions[input.dataset.permissionType],role=input.dataset.permissionRole;if(input.checked&&!list.includes(role))list.push(role);if(!input.checked)p.permissions[input.dataset.permissionType]=list.filter(r=>r!==role);save();renderAll();showToast('อัปเดตสิทธิ์รายโปรเจกต์แล้ว')})};
