$('#planningForm').onsubmit=async e=>{e.preventDefault();const button=e.submitter,p=projects.find(x=>x.id===$('#planProject').value),type=$('#planType').value,file=$('#planFile')?.files[0],record={id:uid(type),title:$('#planTitle').value.trim(),owner:$('#planOwner').value.trim(),start:$('#planStart').value,due:$('#planDue').value,followUp:$('#planFollowUp').value,priority:$('#planPriority').value,note:$('#planNote').value.trim(),progress:0,link:$('#planLink')?.value.trim()||'',fileName:'',storagePath:''};button.disabled=true;try{if(file&&window.LatiteamSupabase){const attachment=await window.LatiteamSupabase.uploadFile(file,p.id);record.storagePath=attachment.storagePath;record.fileName=attachment.fileName;record.link=record.link||attachment.signedUrl}if(type==='workstream'){record.items=[];p.workstreams.push(record)}else{const ws=p.workstreams.find(w=>w.id===$('#planParent').value);if(!ws)return showToast('กรุณาเลือกงานหลัก');ws.items.push(record)}recalculateAll();save();closePlanning();e.target.reset();renderAll();planningShowDetail(p.id);showToast('สร้างงาน Timeline และเอกสารแล้ว')}catch(error){showToast(error.message)}finally{button.disabled=false}};
