function standaloneToAgendaItem(e){const project=e.projectId?projects.find(p=>p.id===e.projectId):null;return{kind:e.type||'general',project,stream:{title:project?'นัดหมายในโปรเจกต์':'งานกลาง'},item:null,title:e.title,owner:e.owner,date:e.date,due:e.date,priority:'medium',note:e.note||'งานหรือนัดหมายที่ไม่รวมใน progress',progress:0,link:e.link,fileName:e.fileName,fileData:e.fileData,id:e.id,isStandalone:true}}
renderAgenda=function(){installAgendaProjectFilters();const q=filterText(uiFilters.agendaSearch);const projectItems=flattenFollowUps().filter(x=>inRange(x.date,uiFilters.agendaStart,uiFilters.agendaEnd)&&projectPass(x.project?.id)&&ownerPass(x.owner)&&(!q||eventSearchText({title:x.title,owner:x.owner,type:x.kind,project:x.project,note:x.note}).includes(q)));const generalItems=standaloneEvents.map(standaloneToAgendaItem).filter(x=>inRange(x.date,uiFilters.agendaStart,uiFilters.agendaEnd)&&projectPass(x.project?.id||'')&&ownerPass(x.owner)&&(!q||[x.title,x.owner,x.note,x.project?.name,'งานกลาง'].join(' ').toLowerCase().includes(q)));const all=[...projectItems,...generalItems].sort((a,b)=>new Date(a.date)-new Date(b.date));const filtered=all.filter(x=>agendaFilter==='all'||followState(x.date)===agendaFilter||x.isStandalone&&agendaFilter==='upcoming');const overdue=all.filter(x=>!x.isStandalone&&followState(x.date)==='overdue').length,today=all.filter(x=>followState(x.date)==='today').length,week=all.filter(x=>dayDiff(x.date,planningToday)>=0&&dayDiff(x.date,planningToday)<=7).length,meetings=filteredCalendarEvents().filter(m=>['meeting','general'].includes(m.type)).length;$('#agendaStats').innerHTML=[['เลยกำหนดติดตาม',overdue,'!','#ef5b5b','เฉพาะงานในโปรเจกต์'],['ต้องติดตามวันนี้',today,'☑','#ff9f43','รวมงานกลางและโปรเจกต์'],['อยู่ในช่วงที่เลือก',week,'◴','#315bea','ตามฟิลเตอร์วันที่'],['ประชุม / งานกลาง',meetings,'◎','#8a5cf6','ไม่รวมใน Progress']].map(x=>`<div class="stat-card" style="--accent:${x[3]}"><div class="stat-top"><span>${x[0]}</span><span class="stat-icon">${x[2]}</span></div><div class="stat-value">${x[1]} รายการ</div><div class="stat-note">${x[4]}</div></div>`).join('');$('#agendaList').innerHTML=filtered.slice(0,40).map(x=>{const state=followState(x.date),projectName=x.project?.name||'งานกลาง';return`<div class="follow-card"><div class="follow-date ${state}">${new Date(x.date+'T00:00:00').getDate()}<small>${new Intl.DateTimeFormat('th-TH',{month:'short'}).format(new Date(x.date+'T00:00:00'))}</small></div><div class="follow-copy"><b>${x.title}${x.isStandalone?'<span class="standalone-badge">ไม่คิด Progress</span>':''}</b><p>${x.note||''}</p><div class="follow-meta"><span class="priority ${x.priority}">${x.isStandalone?'งานกลาง':x.priority==='high'?'สำคัญสูง':x.priority==='medium'?'ปานกลาง':'ทั่วไป'}</span><span>${projectName} › ${x.stream.title}</span><span>ผู้ดูแล ${x.owner}</span></div>${(x.link||x.fileName)?`<div class="attachment-row">${x.link?`<a href="${x.link}" target="_blank" rel="noopener">ลิงก์แนบ</a>`:''}${x.fileName?`<span>ไฟล์: ${x.fileName}</span>`:''}</div>`:''}</div><div class="follow-action"><small>${x.isStandalone?'นัดหมาย':state==='overdue'?`เลยกำหนด ${Math.abs(dayDiff(x.date,planningToday))} วัน`:state==='today'?'ติดตามวันนี้':`อีก ${dayDiff(x.date,planningToday)} วัน`}</small>${x.project?`<button data-open-project="${x.project.id}">เปิดโปรเจกต์</button>`:`<button data-event-id="${x.id}">ดูข้อมูล</button>`}</div></div>`}).join('')||'<div class="empty-state">ไม่มีรายการติดตามตามฟิลเตอร์นี้</div>';renderWeek(projectItems);renderCalendar();renderMonthBoard(dashboardCalendarRootId);$$('[data-open-project]').forEach(b=>b.onclick=()=>showDetail(b.dataset.openProject));$$('[data-event-id]').forEach(b=>b.onclick=()=>openEventPopup(b.dataset.eventId))}

