uiFilters.agendaProject='all';
uiFilters.agendaOwner='all';

function installAgendaProjectFilters(){const bar=$('#agendaSmartFilters');if(!bar||$('#agendaProjectFilter'))return;bar.insertAdjacentHTML('beforeend',`<label><span>ดูแยกโครงการ</span><select id="agendaProjectFilter"><option value="all">ทุกโครงการและงานกลาง</option><option value="general">งานกลาง / ไม่ผูกโปรเจกต์</option>${visibleProjectsByPermission().map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></label><label><span>ผู้ดูแลงาน</span><select id="agendaOwnerFilter"><option value="all">ทุกคน</option>${visibleOwners().map(o=>`<option value="${o}">${o}</option>`).join('')}</select></label>`);$('#agendaProjectFilter').onchange=e=>{uiFilters.agendaProject=e.target.value;renderAgenda()};$('#agendaOwnerFilter').onchange=e=>{uiFilters.agendaOwner=e.target.value;renderAgenda()}}
function projectPass(id){return uiFilters.agendaProject==='all'||uiFilters.agendaProject===id||(uiFilters.agendaProject==='general'&&!id)}
function ownerPass(owner){return uiFilters.agendaOwner==='all'||uiFilters.agendaOwner===owner}

const previousFilteredCalendarEvents=filteredCalendarEvents;
filteredCalendarEvents=function(){const q=filterText(uiFilters.agendaSearch);const projectEvents=enhancedCalendarEvents().filter(e=>inRange(e.date,uiFilters.agendaStart,uiFilters.agendaEnd)&&projectPass(e.project?.id)&&ownerPass(e.owner)&&(!q||eventSearchText(e).includes(q)));const general=standaloneEvents.filter(e=>inRange(e.date,uiFilters.agendaStart,uiFilters.agendaEnd)&&projectPass('')&&ownerPass(e.owner)&&(!q||eventSearchText({title:e.title,owner:e.owner,type:e.type,note:e.note,project:{name:'งานกลาง',client:'',company:''}}).includes(q))).map(e=>({...e,project:null,type:'general'}));return [...projectEvents,...general].sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time))}

function eventProjectId(e){return e.project?.id||e.projectId||''}
function openEventPopup(eventId){const e=filteredCalendarEvents().find(x=>(x.id||`${x.type}-${x.date}-${x.title}`)===eventId);if(!e)return;const project=e.project||projects.find(p=>p.id===e.projectId);$('#eventPopupBody').innerHTML=`<div class="event-popup-body"><div><span class="eyebrow">${project?'PROJECT EVENT':'GENERAL EVENT'}</span><h2>${e.title}${project?'': '<span class="standalone-badge">ไม่คิด Progress</span>'}</h2></div><div class="permission-row"><b>วันที่ / เวลา</b><span>${dateTH(e.date)} ${e.time||''}</span></div><div class="permission-row"><b>โครงการ</b><span>${project?project.name:'งานกลาง ไม่ผูกโปรเจกต์'}</span></div><div class="permission-row"><b>ผู้ดูแล</b><span>${e.owner||'-'}</span></div><div class="permission-row"><b>รายละเอียด</b><span>${e.note||'-'}</span></div>${(e.link||e.fileName)?`<div class="attachment-row">${e.link?`<a href="${e.link}" target="_blank" rel="noopener">เปิดลิงก์แนบ</a>`:''}${e.fileName?`<span>ไฟล์: ${e.fileName}</span>`:''}</div>`:''}</div>`;$('#eventPopupModal').classList.add('open')}
function closeEventPopup(){$('#eventPopupModal').classList.remove('open')}

function renderProjectMiniCalendar(projectId){const root=$('#projectMiniCalendar');if(!root)return;const events=filteredCalendarEvents().filter(e=>eventProjectId(e)===projectId).slice(0,8);root.innerHTML=events.length?events.map(e=>`<div class="mini-cal-event ${e.type}" data-event-id="${e.id||`${e.type}-${e.date}-${e.title}`}"><b>${e.title}</b><small>${dateTH(e.date)} ${e.time||''} · ${e.owner||'-'}</small></div>`).join(''):'<div class="empty-state">ยังไม่มีนัดหรือ timeline ในช่วงที่เลือก</div>';root.querySelectorAll('[data-event-id]').forEach(x=>x.onclick=()=>openEventPopup(x.dataset.eventId))}
function renderExecutivePerformance(projectId){const p=projects.find(x=>x.id===projectId),root=$('#projectPerformance');if(!p||!root)return;const owners={};(p.workstreams||[]).forEach(w=>{owners[w.owner]=owners[w.owner]||[];owners[w.owner].push(w.progress);(w.items||[]).forEach(i=>{owners[i.owner]=owners[i.owner]||[];owners[i.owner].push(i.progress)})});root.innerHTML=Object.entries(owners).map(([owner,vals])=>{const avg=Math.round(vals.reduce((a,b)=>a+b,0)/vals.length);return`<div class="performance-row"><div><b>${owner}</b><small>${vals.length} งาน</small></div><div class="mini-progress"><span style="width:${avg}%;background:${p.color}"></span></div><b>${avg}%</b></div>`}).join('')||'<div class="empty-state">ไม่มีข้อมูล performance</div>'}

const oldPlanningShowDetail=planningShowDetail;
planningShowDetail=function(id){oldPlanningShowDetail(id);const stack=document.querySelector('#projectDetail .detail-side-stack');if(stack&&!$('#projectMiniCalendar')){stack.insertAdjacentHTML('afterbegin',`<div class="panel"><div class="panel-head"><div><span class="eyebrow">PROJECT CALENDAR</span><h3>ปฏิทินโครงการนี้</h3></div><button class="text-button" data-goto="agenda">ดูทั้งหมด</button></div><div id="projectMiniCalendar" class="project-mini-calendar"></div></div><div class="panel executive-performance-panel"><span class="eyebrow">EXECUTIVE PERFORMANCE</span><h3>Performance แยกผู้ดูแล</h3><div id="projectPerformance" class="project-performance"></div></div>`);bindDynamic()}renderProjectMiniCalendar(id);renderExecutivePerformance(id)}
showDetail=planningShowDetail;

function installStandaloneTools(){if(!$('#standaloneEventModal')){document.body.insertAdjacentHTML('beforeend',`<div class="modal-backdrop" id="standaloneEventModal" aria-hidden="true"><div class="modal wide-modal"><div class="modal-head"><div><span class="eyebrow">GENERAL WORK / MEETING</span><h2>เพิ่มงานหรือนัดหมาย</h2></div><button class="close-standalone">×</button></div><form id="standaloneEventForm"><div class="form-row"><label>ผูกกับโครงการหรือไม่<select id="standaloneProject"><option value="">งานกลาง ไม่คิด Progress</option>${projects.map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></label><label>ประเภท<select id="standaloneType"><option value="general">นัดประชุม / งานกลาง</option><option value="meeting">Meeting ในโปรเจกต์</option><option value="follow">Follow-up ในโปรเจกต์</option></select></label></div><label>หัวข้อ<input id="standaloneTitle" required placeholder="เช่น ประชุมสรุปบัญชี / นัดลูกค้า"></label><div class="form-row three"><label>ผู้ดูแล<input id="standaloneOwner" required placeholder="ชื่อผู้รับผิดชอบ"></label><label>วันที่<input id="standaloneDate" type="date" required value="${planningToday}"></label><label>เวลา<input id="standaloneTime" type="time" value="10:00"></label></div><label>รายละเอียด<textarea id="standaloneNote" rows="3" placeholder="รายละเอียด ประเด็นที่ต้องเตรียม หรือผลลัพธ์ที่ต้องการ"></textarea></label><div class="form-row"><label>ลิงก์แนบ<input id="standaloneLink" placeholder="https://..."></label><label>แนบไฟล์<input id="standaloneFile" type="file"></label></div><div class="modal-actions"><button type="button" class="secondary close-standalone">ยกเลิก</button><button type="submit" class="primary">บันทึกนัด / งาน</button></div></form></div></div><div class="modal-backdrop" id="eventPopupModal" aria-hidden="true"><div class="modal"><div class="modal-head"><div><span class="eyebrow">EVENT DETAIL</span><h2>รายละเอียด</h2></div><button class="close-event-popup">×</button></div><div id="eventPopupBody"></div></div></div>`)}
  if(!$('#addStandaloneEvent')){$('#agendaView .section-head .button-row')?.insertAdjacentHTML('afterbegin',`<button class="secondary" id="addStandaloneEvent" type="button">＋ เพิ่มงาน/ประชุมกลาง</button>`)}
  $('#addStandaloneEvent').onclick=()=>$('#standaloneEventModal').classList.add('open');$$('.close-standalone').forEach(b=>b.onclick=()=>$('#standaloneEventModal').classList.remove('open'));$$('.close-event-popup').forEach(b=>b.onclick=closeEventPopup);$('#eventPopupModal').onclick=e=>{if(e.target===$('#eventPopupModal'))closeEventPopup()};$('#standaloneEventForm').onsubmit=saveStandaloneEvent
}
async function saveStandaloneEvent(e){e.preventDefault();const button=e.submitter,file=$('#standaloneFile').files[0],projectId=$('#standaloneProject').value;button.disabled=true;try{const attachment=file?await window.LatiteamSupabase.uploadFile(file,projectId||'general'):{};standaloneEvents.push({id:uid('event'),title:$('#standaloneTitle').value.trim(),date:$('#standaloneDate').value,time:$('#standaloneTime').value,owner:$('#standaloneOwner').value.trim(),type:projectId?$('#standaloneType').value:'general',projectId,note:$('#standaloneNote').value.trim(),link:$('#standaloneLink').value.trim()||attachment.signedUrl||'',fileName:attachment.fileName||'',storagePath:attachment.storagePath||''});saveStandaloneEvents();await window.LatiteamSupabase.push();$('#standaloneEventModal').classList.remove('open');e.target.reset();$('#standaloneDate').value=planningToday;renderAll();showToast('บันทึกงาน/นัดหมายและไฟล์ลง Supabase แล้ว')}catch(error){showToast(error.message)}finally{button.disabled=false}}

const previousRenderMonthBoard=renderMonthBoard;
renderMonthBoard=function(targetId){const root=$('#'+targetId);if(!root)return;const start=calendarMonthStart(),base=new Date(start+'T00:00:00'),year=base.getFullYear(),month=base.getMonth(),firstDay=new Date(year,month,1),pad=firstDay.getDay(),gridStart=new Date(firstDay);gridStart.setDate(firstDay.getDate()-pad);const events=filteredCalendarEvents();const weekdays=['อา','จ','อ','พ','พฤ','ศ','ส'];root.innerHTML=`<div class="ios-calendar"><div class="ios-calendar-top"><div class="ios-calendar-title"><small>Monthly work overview</small><b>${monthNameTH(start)}</b></div><div class="ios-calendar-actions"><span>ค้นหา</span><span>＋</span></div></div><div class="ios-weekdays">${weekdays.map(d=>`<div>${d}</div>`).join('')}</div><div class="ios-month-grid">${Array.from({length:42},(_,i)=>{const d=new Date(gridStart);d.setDate(gridStart.getDate()+i);const iso=localYmd(d),dayEvents=events.filter(e=>e.date===iso),shown=dayEvents.slice(0,5);return`<div class="ios-day ${d.getMonth()!==month?'is-muted':''} ${iso===planningToday?'is-today':''}"><div class="ios-date">${d.getDate()}</div><div class="ios-events">${shown.map(e=>`<div class="ios-event ${e.type}" style="--event-color:${calendarColor(e)}" data-event-id="${e.id||`${e.type}-${e.date}-${e.title}`}"><b>${e.time?e.time+' ':''}${e.title}</b><small>${e.project?.name||'งานกลาง'} · ${e.owner}</small></div>`).join('')}${dayEvents.length>shown.length?`<div class="ios-more">+${dayEvents.length-shown.length} more</div>`:''}</div></div>`}).join('')}</div></div>`;root.querySelectorAll('[data-event-id]').forEach(b=>b.onclick=()=>openEventPopup(b.dataset.eventId))}

const finalRenderAll=renderAll;
renderAll=function(){finalRenderAll();installAgendaProjectFilters();installStandaloneTools();renderMonthBoard(dashboardCalendarRootId)}
installAgendaProjectFilters();
installStandaloneTools();
renderAll();

function filterText(value){return String(value||'').trim().toLowerCase()}
function inRange(date,start,end){if(!date)return true;const d=date.slice(0,10);return (!start||d>=start)&&(!end||d<=end)}
function overlapsRange(start,end,filterStart,filterEnd){const a=start||end,b=end||start;if(!filterStart&&!filterEnd)return true;if(filterStart&&b<filterStart)return false;if(filterEnd&&a>filterEnd)return false;return true}
function projectSearchText(p){return [p.name,p.company,p.client,p.desc,p.manager,(p.team||[]).join(' '),(p.workstreams||[]).map(w=>[w.title,w.owner,w.note,(w.items||[]).map(i=>[i.title,i.owner,i.note].join(' ')).join(' ')].join(' ')).join(' ')].join(' ').toLowerCase()}
function visibleProjectsEnhanced(){return visibleProjectsByPermission().filter(p=>overlapsRange((p.workstreams||[])[0]?.start,p.deadline,uiFilters.projectStart,uiFilters.projectEnd))}
function eventSearchText(e){return [e.title,e.owner,e.type,e.project?.name,e.project?.company,e.project?.client,e.note].join(' ').toLowerCase()}
function enhancedCalendarEvents(){const follow=flattenFollowUps().map(x=>({date:x.date,title:x.title,project:x.project,owner:x.owner,type:'follow',note:x.note}));const meetings=visibleProjectsByPermission().flatMap(p=>(p.meetings||[]).map(m=>({...m,project:p,type:'meeting'})));const due=visibleProjectsByPermission().flatMap(p=>(p.workstreams||[]).map(w=>({date:w.due,title:'Deadline: '+w.title,project:p,owner:w.owner,type:'deadline',note:w.note})));const work=visibleProjectsByPermission().flatMap(p=>(p.workstreams||[]).map(w=>({date:w.start,title:w.title,project:p,owner:w.owner,type:'work',note:w.note})));return [...follow,...meetings,...due,...work]}
function filteredCalendarEvents(){const q=filterText(uiFilters.agendaSearch);return enhancedCalendarEvents().filter(e=>inRange(e.date,uiFilters.agendaStart,uiFilters.agendaEnd)&&(!q||eventSearchText(e).includes(q)))}
function calendarMonthStart(){const src=uiFilters.agendaStart||planningToday;return src.slice(0,7)+'-01'}
function monthNameTH(date){return new Intl.DateTimeFormat('th-TH',{month:'long',year:'numeric'}).format(new Date(date+'T00:00:00'))}
function calendarColor(e){if(e.type==='meeting')return '#64207a';if(e.type==='deadline')return '#7b3d0c';if(e.type==='work')return '#163f5a';return e.project?.color||'#305f33'}
function localYmd(d){return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}
function renderMonthBoard(targetId){const root=$('#'+targetId);if(!root)return;const start=calendarMonthStart(),base=new Date(start+'T00:00:00'),year=base.getFullYear(),month=base.getMonth(),firstDay=new Date(year,month,1),pad=firstDay.getDay(),gridStart=new Date(firstDay);gridStart.setDate(firstDay.getDate()-pad);const events=filteredCalendarEvents();const weekdays=['อา','จ','อ','พ','พฤ','ศ','ส'];root.innerHTML=`<div class="ios-calendar"><div class="ios-calendar-top"><div class="ios-calendar-title"><small>Monthly work overview</small><b>${monthNameTH(start)}</b></div><div class="ios-calendar-actions"><span>ค้นหา</span><span>＋</span></div></div><div class="ios-weekdays">${weekdays.map(d=>`<div>${d}</div>`).join('')}</div><div class="ios-month-grid">${Array.from({length:42},(_,i)=>{const d=new Date(gridStart);d.setDate(gridStart.getDate()+i);const iso=localYmd(d),dayEvents=events.filter(e=>e.date===iso),shown=dayEvents.slice(0,5);return`<div class="ios-day ${d.getMonth()!==month?'is-muted':''} ${iso===planningToday?'is-today':''}"><div class="ios-date">${d.getDate()}</div><div class="ios-events">${shown.map(e=>`<div class="ios-event ${e.type}" style="--event-color:${calendarColor(e)}" data-open-project="${e.project.id}"><b>${e.time?e.time+' ':''}${e.title}</b><small>${e.project.name} · ${e.owner}</small></div>`).join('')}${dayEvents.length>shown.length?`<div class="ios-more">+${dayEvents.length-shown.length} more</div>`:''}</div></div>`}).join('')}</div></div>`;root.querySelectorAll('[data-open-project]').forEach(b=>b.onclick=()=>showDetail(b.dataset.openProject))}
function installSmartFilters(){if(!$('#dashboardMonthOverview')){document.querySelector('#dashboardView .dashboard-grid')?.insertAdjacentHTML('afterend',`<article class="panel month-overview-panel"><div class="month-overview-head"><div><span class="eyebrow">MONTHLY CALENDAR OVERVIEW</span><h3>ภาพรวมงานแบบปฏิทิน</h3></div><div class="calendar-legend"><span><i style="background:#3f9f77"></i>Follow-up</span><span><i style="background:#8a5cf6"></i>Meeting</span><span><i style="background:#f59f34"></i>Deadline</span><span><i style="background:#35a9c8"></i>Workstream</span></div></div><div id="${dashboardCalendarRootId}"></div></article>`)}
  if(!$('#exportDashboardImage')){$('#dashboardView .welcome .primary')?.insertAdjacentHTML('beforebegin',`<button class="secondary export-image-button" id="exportDashboardImage" type="button">Export ภาพรวมเป็นรูป</button>`)}
  if(!$('#dashboardCalendarFilters')){$('#'+dashboardCalendarRootId)?.insertAdjacentHTML('beforebegin',`<div class="smart-filter-bar" id="dashboardCalendarFilters"><label><span>ค้นหาปฏิทินภาพรวม</span><input id="dashboardCalendarSearch" placeholder="ค้นหาชื่องาน โปรเจกต์ ผู้รับผิดชอบ"></label><label><span>วันที่เริ่มต้น</span><input id="dashboardCalendarStart" type="date" value="${uiFilters.agendaStart}"></label><label><span>วันที่สิ้นสุด</span><input id="dashboardCalendarEnd" type="date" value="${uiFilters.agendaEnd}"></label><button class="secondary" id="dashboardCalendarClear" type="button">ล้างฟิลเตอร์</button></div>`)}
  if(!$('#projectStartFilter')){$('#projectsView .toolbar')?.insertAdjacentHTML('beforeend',`<div class="smart-inline-filter"><label>เริ่ม <input id="projectStartFilter" type="date"></label><label>สิ้นสุด <input id="projectEndFilter" type="date"></label><button class="secondary" id="projectFilterClear" type="button">ล้างวันที่</button></div>`)}
  if(!$('#agendaSmartFilters')){$('#agendaStats')?.insertAdjacentHTML('beforebegin',`<div class="smart-filter-bar" id="agendaSmartFilters"><label><span>ค้นหางาน / ผู้รับผิดชอบ / โปรเจกต์</span><input id="agendaSearchFilter" placeholder="เช่น JMT, Onsite, คุณปูลม"></label><label><span>วันที่เริ่มต้น</span><input id="agendaStartFilter" type="date" value="${uiFilters.agendaStart}"></label><label><span>วันที่สิ้นสุด</span><input id="agendaEndFilter" type="date" value="${uiFilters.agendaEnd}"></label><button class="secondary" id="agendaFilterClear" type="button">ล้างฟิลเตอร์</button></div>`)}
  if(!$('#updateSmartFilters')){$('#updatesView .table-panel')?.insertAdjacentHTML('beforebegin',`<div class="smart-filter-bar" id="updateSmartFilters"><label><span>ค้นหาประวัติ</span><input id="updateSearchFilter" placeholder="ชื่อโปรเจกต์ งาน รายละเอียด หรือผู้แก้ไข"></label><label><span>วันที่เริ่มต้น</span><input id="updateStartFilter" type="date"></label><label><span>วันที่สิ้นสุด</span><input id="updateEndFilter" type="date"></label><button class="secondary" id="updateFilterClear" type="button">ล้างฟิลเตอร์</button></div>`)}
  if(!$('#financeSmartFilters')){$('#financeStats')?.insertAdjacentHTML('beforebegin',`<div class="smart-filter-bar" id="financeSmartFilters"><label><span>ค้นหาบริษัท / โปรเจกต์</span><input id="financeSearchFilter" placeholder="ชื่อบริษัท ลูกค้า หรือโปรเจกต์"></label><label><span>เริ่มภายในช่วง</span><input id="financeStartFilter" type="date"></label><label><span>สิ้นสุดภายในช่วง</span><input id="financeEndFilter" type="date"></label><button class="secondary" id="financeFilterClear" type="button">ล้างฟิลเตอร์</button></div>`)}
  bindSmartFilters()
}
function bindSmartFilters(){const bind=(id,key,fn=renderAll)=>{const el=$('#'+id);if(el&&!el.dataset.bound){el.dataset.bound='1';el.oninput=e=>{uiFilters[key]=e.target.value;fn()}}};bind('projectStartFilter','projectStart');bind('projectEndFilter','projectEnd');bind('dashboardCalendarSearch','agendaSearch',renderAll);bind('dashboardCalendarStart','agendaStart',renderAll);bind('dashboardCalendarEnd','agendaEnd',renderAll);bind('agendaSearchFilter','agendaSearch',renderAgenda);bind('agendaStartFilter','agendaStart',renderAgenda);bind('agendaEndFilter','agendaEnd',renderAgenda);bind('updateSearchFilter','updateSearch',renderUpdates);bind('updateStartFilter','updateStart',renderUpdates);bind('updateEndFilter','updateEnd',renderUpdates);bind('financeSearchFilter','financeSearch',renderFinance);bind('financeStartFilter','financeStart',renderFinance);bind('financeEndFilter','financeEnd',renderFinance);
  const bindButton=(id,fn)=>{const b=$('#'+id);if(b&&!b.dataset.bound){b.dataset.bound='1';b.onclick=fn}};
  bindButton('exportDashboardImage',exportDashboardImage);
  bindButton('dashboardCalendarClear',()=>{$('#dashboardCalendarSearch').value='';$('#dashboardCalendarStart').value='2026-06-01';$('#dashboardCalendarEnd').value='2026-06-30';uiFilters.agendaSearch='';uiFilters.agendaStart='2026-06-01';uiFilters.agendaEnd='2026-06-30';renderAll()});
  bindButton('projectFilterClear',()=>{$('#projectStartFilter').value='';$('#projectEndFilter').value='';uiFilters.projectStart='';uiFilters.projectEnd='';renderAll()});
  bindButton('agendaFilterClear',()=>{$('#agendaSearchFilter').value='';$('#agendaStartFilter').value='2026-06-01';$('#agendaEndFilter').value='2026-06-30';uiFilters.agendaSearch='';uiFilters.agendaStart='2026-06-01';uiFilters.agendaEnd='2026-06-30';renderAgenda()});
  bindButton('updateFilterClear',()=>{$('#updateSearchFilter').value='';$('#updateStartFilter').value='';$('#updateEndFilter').value='';uiFilters.updateSearch='';uiFilters.updateStart='';uiFilters.updateEnd='';renderUpdates()});
  bindButton('financeFilterClear',()=>{$('#financeSearchFilter').value='';$('#financeStartFilter').value='';$('#financeEndFilter').value='';uiFilters.financeSearch='';uiFilters.financeStart='';uiFilters.financeEnd='';renderFinance()})
}

function copyComputedStyles(source,target){const style=getComputedStyle(source);target.style.cssText=style.cssText;Array.from(source.children).forEach((child,i)=>copyComputedStyles(child,target.children[i]))}
function exportDashboardImage(){const source=$('#dashboardView');if(!source)return;const clone=source.cloneNode(true);clone.querySelectorAll('input,select').forEach(el=>{if(el.tagName==='INPUT')el.setAttribute('value',el.value||'');if(el.tagName==='SELECT')el.querySelectorAll('option').forEach(o=>o.toggleAttribute('selected',o.selected))});const box=document.createElement('div');box.setAttribute('xmlns','http://www.w3.org/1999/xhtml');box.style.cssText='position:fixed;left:-20000px;top:0;width:1400px;background:#f5f7fb;padding:32px';box.appendChild(clone);document.body.appendChild(box);copyComputedStyles(source,clone);clone.querySelector('#exportDashboardImage')?.remove();const width=box.offsetWidth,height=clone.scrollHeight+64,html=new XMLSerializer().serializeToString(box);const svg=`<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}"><foreignObject width="100%" height="100%">${html}</foreignObject></svg>`;const img=new Image();const url=URL.createObjectURL(new Blob([svg],{type:'image/svg+xml;charset=utf-8'}));img.onload=()=>{const canvas=document.createElement('canvas');canvas.width=width*2;canvas.height=height*2;const ctx=canvas.getContext('2d');ctx.scale(2,2);ctx.fillStyle='#f5f7fb';ctx.fillRect(0,0,width,height);ctx.drawImage(img,0,0);URL.revokeObjectURL(url);document.body.removeChild(box);const a=document.createElement('a');a.href=canvas.toDataURL('image/png');a.download=`latiteam-dashboard-${planningToday}.png`;a.click();showToast('Export ภาพรวมองค์กรเป็นรูป PNG แล้ว')};img.onerror=()=>{URL.revokeObjectURL(url);document.body.removeChild(box);showToast('Export รูปไม่สำเร็จ กรุณาลองใหม่อีกครั้ง')};img.src=url}

