function installFinanceTransactionEditor(){
  if($('#financeTransactionModal'))return;
  document.body.insertAdjacentHTML('beforeend',`<div class="modal-backdrop" id="financeTransactionModal"><div class="modal wide-modal"><div class="modal-head"><div><span class="eyebrow">PAYMENT & EXPENSE LEDGER</span><h2>บันทึกรายการรับ–จ่าย</h2></div><button class="close-finance-transaction">×</button></div><form id="financeTransactionForm"><input type="hidden" id="transactionId"><div class="form-row"><label>โปรเจกต์<select id="transactionProject" required></select></label><label>ประเภทรายการ<select id="transactionType"><option value="income">รับเงิน / ลูกค้าชำระ</option><option value="expense">ค่าใช้จ่าย / จ่ายเงิน</option></select></label></div><div class="form-row three"><label>วันที่<input id="transactionDate" type="date" required></label><label>จำนวนเงิน (บาท)<input id="transactionAmount" type="number" min="0.01" step="0.01" required></label><label>หมวดหมู่<input id="transactionCategory" list="financeCategoryList" required placeholder="เลือกหรือพิมพ์เพิ่ม"></label></div><datalist id="financeCategoryList"><option value="เงินงวดจากลูกค้า"><option value="ค่าบริการ"><option value="ค่าจ้างทีมงาน"><option value="ค่าเดินทาง"><option value="ค่าที่พัก"><option value="ค่าอาหาร"><option value="ค่าซอฟต์แวร์"><option value="ค่าอุปกรณ์"><option value="ภาษีและค่าธรรมเนียม"><option value="ค่าใช้จ่ายอื่น"></datalist><div class="form-row"><label>ผู้รับเงิน / ผู้จ่ายเงิน / คู่ค้า<input id="transactionCounterparty"></label><label>เลขที่อ้างอิง<input id="transactionReference" placeholder="เลขใบเสร็จ เลขสลิป หรือเลขเอกสาร"></label></div><label>รายละเอียด<textarea id="transactionDescription" rows="3" placeholder="รายละเอียดงวดหรือวัตถุประสงค์ค่าใช้จ่าย"></textarea></label><label>เอกสารแนบ<input id="transactionFile" type="file" accept="image/jpeg,image/png,image/webp,application/pdf,.xlsx,.docx"><small>รองรับสลิป ใบเสร็จ ใบแทนใบเสร็จ PDF รูปภาพ Excel และ Word ไม่เกิน 20 MB</small></label><div id="currentTransactionDocument" class="current-document"></div><div class="modal-actions"><button type="button" class="secondary close-finance-transaction">ยกเลิก</button><button class="primary" type="submit">บันทึกรายการ</button></div></form></div></div>`);
  $$('.close-finance-transaction').forEach(button=>button.onclick=()=>$('#financeTransactionModal').classList.remove('open'));$('#financeTransactionForm').onsubmit=saveTransactionForm;
}
function openFinanceTransaction(id=''){installFinanceTransactionEditor();const item=financeTransactions.find(transaction=>transaction.id===id),allowed=editableFinanceProjects();$('#transactionProject').innerHTML=allowed.map(project=>`<option value="${project.id}">${project.name}</option>`).join('');$('#transactionId').value=item?.id||'';$('#transactionProject').value=item?.projectId||allowed[0]?.id||'';$('#transactionProject').disabled=Boolean(item);$('#transactionType').value=item?.type||'expense';$('#transactionDate').value=item?.date||new Date().toISOString().slice(0,10);$('#transactionAmount').value=item?.amount||'';$('#transactionCategory').value=item?.category||'';$('#transactionCounterparty').value=item?.counterparty||'';$('#transactionReference').value=item?.referenceNo||'';$('#transactionDescription').value=item?.description||'';$('#transactionFile').value='';$('#currentTransactionDocument').innerHTML=item?.documentUrl?`<a href="${item.documentUrl}" target="_blank" rel="noopener">เปิดเอกสารปัจจุบัน: ${item.fileName||'เอกสารแนบ'}</a>`:'';$('#financeTransactionModal h2').textContent=item?'แก้ไขรายการรับ–จ่าย':'บันทึกรายการรับ–จ่าย';$('#financeTransactionModal').classList.add('open')}
async function saveTransactionForm(event){event.preventDefault();const button=event.submitter,id=$('#transactionId').value,existing=financeTransactions.find(transaction=>transaction.id===id),file=$('#transactionFile').files[0],item={id:id||'',projectId:$('#transactionProject').value,type:$('#transactionType').value,date:$('#transactionDate').value,amount:Number($('#transactionAmount').value),category:$('#transactionCategory').value.trim(),counterparty:$('#transactionCounterparty').value.trim(),referenceNo:$('#transactionReference').value.trim(),description:$('#transactionDescription').value.trim(),storagePath:existing?.storagePath||'',fileName:existing?.fileName||'',documentUrl:existing?.documentUrl||''};button.disabled=true;try{if(file)Object.assign(item,await window.LatiteamSupabase.uploadAccountingDocument(file,item.projectId));await window.LatiteamSupabase.saveFinanceTransaction(item);const index=financeTransactions.findIndex(transaction=>transaction.id===item.id);if(index>=0)financeTransactions[index]=item;else financeTransactions.unshift(item);applyLedgerTotals();const project=projects.find(p=>p.id===item.projectId);if(project)await window.LatiteamSupabase.saveFinance(project);$('#financeTransactionModal').classList.remove('open');renderAll();showToast('บันทึกรายการและเอกสารบัญชีแล้ว')}catch(error){showToast(error.message)}finally{button.disabled=false}}
async function removeFinanceTransaction(id){const item=financeTransactions.find(transaction=>transaction.id===id);if(!item||!confirm('ลบรายการรับ–จ่ายนี้ใช่หรือไม่'))return;try{await window.LatiteamSupabase.deleteFinanceTransaction(id);financeTransactions=financeTransactions.filter(transaction=>transaction.id!==id);applyLedgerTotals();const project=projects.find(p=>p.id===item.projectId);if(project)await window.LatiteamSupabase.saveFinance(project);renderAll();showToast('ลบรายการแล้ว')}catch(error){showToast(error.message)}}
function applyLedgerTotals(){projects.forEach(project=>{const rows=financeTransactions.filter(item=>item.projectId===project.id);if(!rows.length)return;const received=rows.filter(item=>item.type==='income').reduce((sum,item)=>sum+Number(item.amount||0),0),expense=rows.filter(item=>item.type==='expense').reduce((sum,item)=>sum+Number(item.amount||0),0);project.cost=expense;project.received=received;project.paid=`รับแล้ว ${money(received)} / คงเหลือ ${money(Math.max(0,Number(project.value||0)-received))}`})}
function renderFinanceLedger(){let panel=$('#financeLedgerPanel');if(!panel){$('#financeView .table-panel')?.insertAdjacentHTML('afterend',`<section class="panel finance-ledger-panel" id="financeLedgerPanel"><div class="panel-head"><div><span class="eyebrow">PAYMENT & EXPENSE LEDGER</span><h3>รายการรับเงินและค่าใช้จ่าย</h3><p>หนึ่งโปรเจกต์บันทึกได้หลายงวด หลายค่าใช้จ่าย และแนบเอกสารต่อรายการ</p></div><select id="ledgerTypeFilter"><option value="all">รับ–จ่ายทั้งหมด</option><option value="income">เฉพาะรับเงิน</option><option value="expense">เฉพาะค่าใช้จ่าย</option></select></div><div class="table-wrap"><table><thead><tr><th>วันที่</th><th>โปรเจกต์</th><th>ประเภท</th><th>หมวดหมู่ / รายละเอียด</th><th>คู่ค้า / อ้างอิง</th><th>จำนวนเงิน</th><th>เอกสาร</th><th>จัดการ</th></tr></thead><tbody id="financeLedgerRows"></tbody></table></div></section>`);panel=$('#financeLedgerPanel');$('#ledgerTypeFilter').onchange=renderFinanceLedger}const filter=$('#ledgerTypeFilter')?.value||'all',allowed=new Set(editableFinanceProjects().map(project=>project.id)),rows=financeTransactions.filter(item=>allowed.has(item.projectId)&&(filter==='all'||item.type===filter)&&inRange(item.date,uiFilters.financeStart,uiFilters.financeEnd)).sort((a,b)=>(b.date||'').localeCompare(a.date||''));$('#financeLedgerRows').innerHTML=rows.map(item=>{const project=projects.find(p=>p.id===item.projectId);return`<tr><td>${dateTH(item.date)}</td><td><b>${project?.name||'-'}</b></td><td><span class="transaction-type ${item.type}">${item.type==='income'?'รับเงิน':'ค่าใช้จ่าย'}</span></td><td><b>${item.category}</b><small>${item.description||'-'}</small></td><td>${item.counterparty||'-'}<small>${item.referenceNo||''}</small></td><td class="transaction-amount ${item.type}">${item.type==='income'?'+':'-'}${money(item.amount)}</td><td>${item.documentUrl?`<a class="document-link" href="${item.documentUrl}" target="_blank" rel="noopener">${item.fileName||'เปิดเอกสาร'}</a>`:'-'}</td><td><div class="ledger-actions"><button type="button" data-edit-transaction="${item.id}">แก้ไข</button><button type="button" class="delete" data-delete-transaction="${item.id}">ลบ</button></div></td></tr>`}).join('')||'<tr><td colspan="8" class="empty-state">ยังไม่มีรายการรับ–จ่าย</td></tr>';$$('[data-edit-transaction]').forEach(button=>button.onclick=()=>openFinanceTransaction(button.dataset.editTransaction));$$('[data-delete-transaction]').forEach(button=>button.onclick=()=>removeFinanceTransaction(button.dataset.deleteTransaction))}

function refreshManagementUi(){installProjectEditor();installFinanceEditor();installFinanceTransactionEditor();organizeDashboardActions();installNotificationCenter();renderNotificationCenter();const financeHead=$('#financeView .section-head');if(financeHead&&!$('#openFinanceTransaction'))financeHead.insertAdjacentHTML('beforeend','<button class="primary" id="openFinanceTransaction" type="button">+ บันทึกรายการรับ / จ่าย</button>');if(financeHead&&!$('#openFinanceEditor'))financeHead.insertAdjacentHTML('beforeend','<button class="secondary" id="openFinanceEditor" type="button">แก้ไขยอดตั้งต้น</button>');if($('#openFinanceTransaction'))$('#openFinanceTransaction').onclick=()=>openFinanceTransaction();if($('#openFinanceEditor'))$('#openFinanceEditor').onclick=()=>openFinanceEdit();renderFinanceLedger()}
const managementRenderAll=renderAll;
renderAll=function(){applyLedgerTotals();managementRenderAll();refreshManagementUi()}
refreshManagementUi();

/* Attachments for every project update and project calendar entry */
function recordAttachmentMarkup(record){if(!record?.link&&!record?.fileName)return'';return`<div class="record-attachment">${record.link?`<a href="${record.link}" target="_blank" rel="noopener">เปิดเอกสาร${record.fileName?`: ${record.fileName}`:''}</a>`:`<span>ไฟล์: ${record.fileName}</span>`}</div>`}
function renderProjectRecordAttachments(projectId){const project=projects.find(item=>item.id===projectId);if(!project)return;(project.workstreams||[]).forEach(stream=>{const root=$(`[data-workstream="${stream.id}"]`);const follow=root?.querySelector('.next-follow');if(follow&&!follow.querySelector('.record-attachment'))follow.insertAdjacentHTML('beforeend',recordAttachmentMarkup(stream));(stream.items||[]).forEach(item=>{const row=$(`[data-progress-item="${item.id}"][data-stream-id="${stream.id}"]`)?.closest('.check-row'),copy=row?.querySelector('.check-copy');if(copy&&!copy.querySelector('.record-attachment'))copy.insertAdjacentHTML('beforeend',recordAttachmentMarkup(item))})})}
function ensureTaskAttachmentFields(){const form=$('#editTaskForm');if(!form||$('#editTaskLink'))return;form.querySelector('.modal-actions').insertAdjacentHTML('beforebegin',`<div class="form-row"><label>ลิงก์เอกสาร<input id="editTaskLink" type="url" placeholder="https://..."></label><label>แนบไฟล์ใหม่<input id="editTaskFile" type="file"><small>ไฟล์ใหม่จะแทนเอกสารแนบเดิม</small></label></div><div id="editTaskCurrentFile" class="current-document"></div>`)}
const attachmentOpenEditTask=openEditTask;
openEditTask=function(projectId,streamId,itemId){attachmentOpenEditTask(projectId,streamId,itemId);ensureTaskAttachmentFields();const project=projects.find(item=>item.id===projectId),stream=project?.workstreams.find(item=>item.id===streamId),record=stream?.items.find(item=>item.id===itemId);$('#editTaskLink').value=record?.link||'';$('#editTaskFile').value='';$('#editTaskCurrentFile').innerHTML=record?.link?`<a href="${record.link}" target="_blank" rel="noopener">เปิดเอกสารปัจจุบัน${record.fileName?`: ${record.fileName}`:''}</a>`:'';$('#editTaskForm').onsubmit=saveEditedTaskWithAttachment}
async function saveEditedTaskWithAttachment(event){event.preventDefault();const button=event.submitter,project=projects.find(item=>item.id===$('#editProjectId').value),stream=project?.workstreams.find(item=>item.id===$('#editStreamId').value),record=stream?.items.find(item=>item.id===$('#editItemId').value),file=$('#editTaskFile').files[0];if(!record)return;button.disabled=true;try{if(file&&window.LatiteamSupabase){const attachment=await window.LatiteamSupabase.uploadFile(file,project.id);record.storagePath=attachment.storagePath;record.fileName=attachment.fileName;record.link=attachment.signedUrl}else record.link=$('#editTaskLink').value.trim();saveEditedTask(event);showToast('บันทึกงานและเอกสารแนบแล้ว')}catch(error){showToast(error.message)}finally{button.disabled=false}}
function openProjectMeeting(projectId){installStandaloneTools();const form=$('#standaloneEventForm');form.reset();$('#standaloneProject').value=projectId;$('#standaloneType').value='meeting';$('#standaloneDate').value=new Date().toISOString().slice(0,10);$('#standaloneTime').value='10:00';$('#standaloneEventModal').classList.add('open')}
function enhanceProjectCalendarActions(projectId){const calendar=$('#projectMiniCalendar');if(!calendar)return;const head=calendar.closest('.panel')?.querySelector('.panel-head');if(head&&!head.querySelector('[data-add-project-meeting]'))head.insertAdjacentHTML('beforeend',`<button class="primary compact-button" type="button" data-add-project-meeting="${projectId}">+ เพิ่มประชุม / นัดหมาย</button>`);$$('[data-add-project-meeting]').forEach(button=>button.onclick=()=>openProjectMeeting(button.dataset.addProjectMeeting))}
const attachmentDetailRenderer=showDetail;
showDetail=function(id){attachmentDetailRenderer(id);renderProjectRecordAttachments(id);enhanceProjectCalendarActions(id)}
planningShowDetail=showDetail;
const updateAttachmentRenderer=renderUpdates;
renderUpdates=function(){updateAttachmentRenderer();const allowed=visibleProjectsByPermission().map(project=>project.id),q=filterText(uiFilters.updateSearch),list=updates.filter(item=>allowed.includes(item.project)&&inRange(item.date,uiFilters.updateStart,uiFilters.updateEnd)).filter(item=>{const project=projects.find(value=>value.id===item.project);return !q||[project?.name,project?.client,item.task,item.note,item.user].join(' ').toLowerCase().includes(q)});$$('#updateTable tr').forEach((row,index)=>{const cell=row.children[3],item=list[index];if(cell&&item&&!cell.querySelector('.record-attachment'))cell.insertAdjacentHTML('beforeend',recordAttachmentMarkup(item))})}
